import { useCallback, useState } from "react";
import { TradersData } from "../../utils/dataTypesUtils";

export function useTraders(channel: string = "channel-a") {
  const [data, setData] = useState<TradersData | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  const fetchTraders = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch(`${host}/traders/channel-a`, {
        method: httpMethod.GET,
        headers: { "Content-Type": "application/json" },
      });

      if (response.ok) {
        const responseData = await response.json();
        let parsedTraders = [];
        if (responseData.Traders) {
          try {
            parsedTraders = JSON.parse(responseData.Traders);
            if (!Array.isArray(parsedTraders)) {
              parsedTraders = [];
            }
          } catch (parseError) {
            console.warn(
              `Failed to parse traders, defaulting to empty array`,
              parseError
            );
            parsedTraders = [];
          }
        }

        const parsedData = {
          ...responseData,
          Traders: parsedTraders,
        };
        setData(parsedData);
      } else {
        const errorData = await response.json();
        setError(errorData.Message || "Failed to fetch traders");
      }
    } catch (err) {
      setError(
        `Error connecting to server: ${
          err instanceof Error ? err.message : String(err)
        }`
      );
    } finally {
      setLoading(false);
    }
  }, [channel]);
}
